+fn redacted_mcp_error_message(error: &Error, code: &'static str) -> String {
+    match (code, error) {
+        (MCP_ERR_STORAGE, _) => "Storage unavailable".to_string(),
+        (MCP_ERR_NOT_IMPLEMENTED, Error::Runtime(_)) => "Runtime unavailable".to_string(),
